import{_ as t,a,b as r,c as o,d as n,e as l,f as i,g as s}from"./chunks/spinner.zDAoPV7M.js";import{_ as p,c as h,o as c,ag as u}from"./chunks/framework.DRADY2L-.js";const _=JSON.parse('{"title":"Everything about Waterproofing","description":"Flying in snow or rain without waterproofing is a risky endeavor for drones. If moisture gets onto active electronics, glitches such as sudden motor failure ...","frontmatter":{"description":"Flying in snow or rain without waterproofing is a risky endeavor for drones. If moisture gets onto active electronics, glitches such as sudden motor failure ...","gitAuthors":["mituritsyn","ikherty","Valentina Petrenko","Andrey","Dmitry Volovod"]},"headers":[],"relativePath":"community/coating.md","filePath":"en/community/coating.md","lastUpdated":1771019108000}'),d={name:"community/coating.md"};function m(f,e,b,g,y,w){return c(),h("div",null,[...e[0]||(e[0]=[u('<h1 id="everything-about-waterproofing" tabindex="-1">Everything about Waterproofing <a class="header-anchor" href="#everything-about-waterproofing" aria-label="Permalink to &quot;Everything about Waterproofing&quot;">​</a></h1><p>Flying in snow or rain without waterproofing is a risky endeavor for drones. If moisture gets onto active electronics, glitches such as sudden motor failure or loss of connection are likely (and in most cases, occur). Falling into salt water (the sea) leads to oxidation and circuit damage.</p><h2 id="what-should-be-covered-with-sealant" tabindex="-1">What should be covered with sealant? <a class="header-anchor" href="#what-should-be-covered-with-sealant" aria-label="Permalink to &quot;What should be covered with sealant?&quot;">​</a></h2><p>For maximum protection, you need to cover all the legs of electronic board elements. If the legs are <a href="https://yandex.ru/images/search?from=tabbar&amp;text=bga%20qnf%20%D0%BA%D0%BE%D1%80%D0%BF%D1%83%D1%81%20smd" target="_blank" rel="noreferrer">under the housing</a>, you should apply sealant around the perimeter of the housing. It is not necessary to apply it to the black bodies of the elements themselves, but for <a href="https://yandex.ru/images/search?from=tabbar&amp;text=smd%20capacitor" target="_blank" rel="noreferrer">capacitors</a> and <a href="https://yandex.ru/images/search?from=tabbar&amp;text=smd%20resistor" target="_blank" rel="noreferrer">resistors</a>, sealant should be applied over the elements, preferably in a thicker layer, as part of the sealant may run off, leaving a poorly coated surface. You should <strong>pay attention to the <a href="https://yandex.ru/images/search?from=tabbar&amp;text=barometer%20sensor%20bmp280%20DPS310%20smd" target="_blank" rel="noreferrer">barometer</a></strong>; if one is present and you plan to use it, under no circumstances should you <strong>let anything get into its opening</strong>. You can cover the barometer housing with tape before applying the sealant. Additionally, do not allow sealant to get into the microSD card slot or USB connector; you should insert plugs before application. The contacts of connectors can be covered from the inside with plugs to prevent sealant entry, or sealed over if you are sure you won&#39;t use them. It is recommended to apply sealant at the base of the silicone insulation of the connector wires to prevent moisture from entering the connectors.</p><p>Components like air units and transmitters with screens can be coated around the perimeter of the heatsink/shield, or disassembled and coated according to the advice above. If you are unsure about disassembly, it&#39;s better not to risk it and only coat the perimeter; this should handle accidental moisture from grass or rain.</p><p>It is also recommended to cover contacts with sealant after soldering.</p><h2 id="what-are-the-options-for-waterproofing-electronics" tabindex="-1">What are the options for waterproofing electronics? <a class="header-anchor" href="#what-are-the-options-for-waterproofing-electronics" aria-label="Permalink to &quot;What are the options for waterproofing electronics?&quot;">​</a></h2><p>As of 2024, the following options are relevant:</p><ul><li>Kotking</li><li>Silicone Glue 705</li><li>B-7000 Glue</li><li>FX FPV AeroX V2 Silicone Sealant</li><li>FX FPV Aero WARP Silicone Varnish</li><li>FX FPV Aero Light Silicone Varnish</li><li>DCA Electrolube</li><li>Spinner Protection Silicone Conformal Coating V2 (&quot;Spinner Liquid&quot;)</li><li>Chinese IP65 Silicone Circuit Protection</li></ul><p>A bit about each of them:</p><h2 id="kotking-if-unavailable-here-look-on-team-blacksheep-or-market-boards" tabindex="-1">KOTKING, <a href="https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=339&amp;search=kotking" target="_blank" rel="noreferrer">if unavailable here, look on Team BlackSheep or market boards</a> <a class="header-anchor" href="#kotking-if-unavailable-here-look-on-team-blacksheep-or-market-boards" aria-label="Permalink to &quot;KOTKING, [if unavailable here, look on Team BlackSheep or market boards](https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=339&amp;search=kotking)&quot;">​</a></h2><p>Silicone. Kotking was a premium product for a long time, sold mainly abroad, and the price was always higher than analogues. It has become more accessible now thanks to some stores, though the price is still slightly higher than some alternatives. It comes in a small tube with liquid silicone inside. One tube is enough to cover 3-4 drones (electronics) with a moderate layer. It is applied from the tube as a relatively thick drop and spread with a stick over the entire area, or squeezed through an additional nozzle with a narrow opening (remember to clean it or wrap it tightly afterward so it can be reused). According to the instructions, it should set in 15-20 minutes, but personal experience has varied; sometimes it was very liquid and took 12-16 hours to set, and over a day to fully cure. Yet, even the liquid version stored well for 2-3 months on a shelf without losing its properties. There is an unpleasant odor until it dries. The coating is quite reliable, as demonstrated by videos of drones working perfectly underwater. However, practice has shown that after 24-48 hours in a body of water, some electronics still fail; unfortunately, there are no 100% guarantees. If not manually disturbed, it remains as a solid layer and protects boards excellently. It is impossible to solder through the applied layer. Removing it isn&#39;t particularly convenient; you can&#39;t just peel the whole layer off; it comes off in pieces. It is not soluble in acetone. Presumably, most of it can be removed using Solvent 646 and a brush, but like any other silicone, it will remain between the legs of components, which usually bothers electronics repair technicians. One significant downside: with long-term storage (several months), it can cure inside the tube, though it still stores better in its packaging than alternatives in varnish-like tubes. In summary:</p><ul><li><p>Relatively reliable moisture protection</p></li><li><p>The layer is not damaged without external influence</p></li><li><p>Can be hard to find in Russia</p></li><li><p>Expensive ($12 for 15ml)</p></li><li><p>Complaints that it can cure even in sealed form during long storage</p></li><li><p>One tube covers 3-4 drones at most</p></li><li><p>Unpleasant odor before drying</p></li><li><p>Hard to clean off the board</p></li><li><p>Cannot solder through the layer; must be scraped off for repairs</p></li></ul><p align="center"><img src="'+t+'" width="600" alt="KOTKING"></p><h2 id="glue-705-buy-it-here" tabindex="-1">Glue 705, <a href="https://air-hobby.ru/katalog/product/3737-silikonoviy-kley-germetik-705-prozrachniy-50-ml.html" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#glue-705-buy-it-here" aria-label="Permalink to &quot;Glue 705, [buy it here](https://air-hobby.ru/katalog/product/3737-silikonoviy-kley-germetik-705-prozrachniy-50-ml.html)&quot;">​</a></h2><p>Silicone. Although described as a glue, it performs well as a sealant. Also found as K-705. Applied as a thick drop from the tube and spread with a stick, or through a fine nozzle. Sets in 20-30 minutes if not applied too thickly. Properties are similar to Kotking. Practically odorless. Summary:</p><ul><li><p>Cheap (under 300 RUB for a 45g tube)</p></li><li><p>Widely available</p></li><li><p>Relatively reliable moisture protection</p></li><li><p>Practically no smell</p></li><li><p>Fast drying with a moderate layer</p></li><li><p>The layer is not damaged without external influence</p></li><li><p>Not soluble in acetone; soaking in gasoline for 10-15 minutes might help</p></li><li><p>Cannot solder through the layer; must be scraped off for repairs</p></li></ul><p align="center"><img src="'+a+'" width="600" alt="705"></p><h2 id="b-7000-glue-buy-it-here" tabindex="-1">B-7000 Glue, <a href="https://www.wildberries.ru/catalog/14059777/detail.aspx" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#b-7000-glue-buy-it-here" aria-label="Permalink to &quot;B-7000 Glue, [buy it here](https://www.wildberries.ru/catalog/14059777/detail.aspx)&quot;">​</a></h2><p>Despite being a glue, B-7000 also excels at waterproofing and is resistant to temperatures reached by electronics during idle time. It&#39;s cheap, available in various tube sizes, and sold in many places. However, there are many manufacturers (some counted at least 15), and the consistency can vary slightly. Good versions are liquid enough to apply easily, and the layer is transparent and cures without air bubbles (clean the board before application). If yours is very viscous/yellowish, it&#39;s either been stored too long or is from a poor batch. Sets in 15-30 minutes; full curing takes several hours. You can solder through it, but it&#39;s not pleasant due to the terrible smell. If you have a good version, it can be removed by picking at an edge and winding it onto tweezers. If you&#39;re unlucky with the manufacturer, it only comes off after soaking in acetone for 10 minutes or by winding it after heating, but there&#39;s a risk of pulling off SMD components. After coating with B-7000 and drying, it&#39;s recommended to wipe the coating with alcohol. This makes the surface slightly matte and stops it from being sticky (so it won&#39;t collect debris). Many repair technicians prefer this sealant because it protects well and can be removed from entire sections of the board. Alternatives like T-7000, E-6000, and E-8000 have similar characteristics but different colors. Summary:</p><ul><li><p>Cheap (under 200 RUB for up to 50ml)</p></li><li><p>Widely available</p></li><li><p>Easy to apply</p></li><li><p>Reliable moisture protection</p></li><li><p>Fast drying</p></li><li><p>Occasional &quot;bad&quot; batches</p></li><li><p>Pungent smell when soldering through it</p></li><li><p>Risk of pulling off SMD components during removal</p></li></ul><p align="center"><img src="'+r+'" width="600" alt="B-7000"></p><h2 id="fx-fpv-aerox-v2-silicone-sealant-buy-it-here" tabindex="-1">FX FPV AeroX V2 Silicone Sealant, <a href="https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=328" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#fx-fpv-aerox-v2-silicone-sealant-buy-it-here" aria-label="Permalink to &quot;FX FPV AeroX V2 Silicone Sealant, [buy it here](https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=328)&quot;">​</a></h2><p>Silicone. Reminiscent of its first version (see the Legacy section), but with a different tube and slightly modified formula; the problem of curing inside the tube during storage has been addressed (though it can still cure if stored for a very long time or left open). Available in 20 and 30ml in transparent and black (FX FPV AeroX Black); properties are identical. Pleasant smell. Sets in 20 minutes. Transparent layer with no bubbles. Cannot solder through it. One removal method is soaking in <a href="https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=327" target="_blank" rel="noreferrer">Aero Remover</a>. Detailed review <a href="https://youtu.be/inSmXQqUkCw" target="_blank" rel="noreferrer">here</a>. Summary:</p><ul><li><p>Easy application</p></li><li><p>Pleasant smell</p></li><li><p>Fast drying (20 min)</p></li><li><p>Durable layer</p></li><li><p>Relatively reliable protection</p></li><li><p>Cannot solder through it</p></li><li><p>Expensive (~850 RUB per tube)</p></li><li><p>Only available in Russia</p></li></ul><p align="center"><img src="'+o+'" width="600" alt="Aero X V2"></p><h2 id="fx-fpv-aero-warp-silicone-varnish-buy-it-here" tabindex="-1">FX FPV Aero WARP Silicone Varnish, <a href="https://mydrone.ru/?match=all&amp;subcats=Y&amp;pcode_from_q=Y&amp;pshort=Y&amp;pfull=Y&amp;pname=Y&amp;pkeywords=Y&amp;search_performed=Y&amp;q=Aero&amp;dispatch=products.search&amp;security_hash=f42b3402778c170a04c1f0df572242c6" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#fx-fpv-aero-warp-silicone-varnish-buy-it-here" aria-label="Permalink to &quot;FX FPV Aero WARP Silicone Varnish, [buy it here](https://mydrone.ru/?match=all&amp;subcats=Y&amp;pcode_from_q=Y&amp;pshort=Y&amp;pfull=Y&amp;pname=Y&amp;pkeywords=Y&amp;search_performed=Y&amp;q=Aero&amp;dispatch=products.search&amp;security_hash=f42b3402778c170a04c1f0df572242c6)&quot;">​</a></h2><p>Silicone varnish. No toxic smell. Comes in a tube, which allows for long storage life. Sets in 20 minutes. The cured layer is viscous and doesn&#39;t crack. You can solder through the cured layer. Similar to the <a href="https://propwashservice.com/community/coating.html#Chinese-IP65-Circuit-Protection" target="_blank" rel="noreferrer">Chinese IP65 circuit protection</a>. One removal method is soaking in <a href="https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=327" target="_blank" rel="noreferrer">Aero Remover</a>. Detailed review <a href="https://youtu.be/inSmXQqUkCw" target="_blank" rel="noreferrer">here</a>. Summary:</p><ul><li><p>Mid-range price (~600 RUB per tube)</p></li><li><p>Can solder through it</p></li><li><p>Doesn&#39;t crack</p></li><li><p>Acceptable smell</p></li><li><p>Fast drying (20 min)</p></li><li><p>Relatively reliable protection</p></li><li><p>Only available in Russia</p></li></ul><p align="center"><img src="'+n+'" width="600" alt="Aero WARP"></p><h2 id="fx-fpv-aero-light-silicone-varnish-buy-it-here" tabindex="-1">FX FPV Aero Light Silicone Varnish, <a href="https://mydrone.ru/?match=all&amp;subcats=Y&amp;pcode_from_q=Y&amp;pshort=Y&amp;pfull=Y&amp;pname=Y&amp;pkeywords=Y&amp;search_performed=Y&amp;q=Aero&amp;dispatch=products.search&amp;security_hash=f42b3402778c170a04c1f0df572242c6" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#fx-fpv-aero-light-silicone-varnish-buy-it-here" aria-label="Permalink to &quot;FX FPV Aero Light Silicone Varnish, [buy it here](https://mydrone.ru/?match=all&amp;subcats=Y&amp;pcode_from_q=Y&amp;pshort=Y&amp;pfull=Y&amp;pname=Y&amp;pkeywords=Y&amp;search_performed=Y&amp;q=Aero&amp;dispatch=products.search&amp;security_hash=f42b3402778c170a04c1f0df572242c6)&quot;">​</a></h2><p>Silicone varnish. Has a slight chemical smell but with added fragrance. The fragrance remains after the layer cures. Comes in a tube for long shelf life (previously sold in jars with brushes, where users complained about it drying out). Sets in 15-20 minutes. The cured layer is viscous and doesn&#39;t crack. You can solder through it. Similar to <a href="https://propwashservice.com/community/coating.html#Chinese-IP65-Circuit-Protection" target="_blank" rel="noreferrer">Chinese IP65 circuit protection</a>. One removal method is soaking in <a href="https://www.fpvmatrix.ru/index.php?route=product/product&amp;product_id=327" target="_blank" rel="noreferrer">Aero Remover</a>. Detailed review <a href="https://youtu.be/inSmXQqUkCw" target="_blank" rel="noreferrer">here</a>. Summary:</p><ul><li><p>Mid-range price (~650 RUB per tube)</p></li><li><p>Can solder through it</p></li><li><p>Doesn&#39;t crack</p></li><li><p>Pleasant smell</p></li><li><p>Fast drying (15-20 min)</p></li><li><p>Relatively reliable protection</p></li><li><p>Only available in Russia</p></li></ul><p align="center"><img src="'+l+'" width="600" alt="Aero Light"></p><h2 id="dca-electrolube-buy-it-here" tabindex="-1">DCA Electrolube, <a href="https://air-hobby.ru/katalog/product/2286-dca-electrolube-prozrachniy-lak-na-osnove-modifitsirovannogo-silikona-20ml.html" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#dca-electrolube-buy-it-here" aria-label="Permalink to &quot;DCA Electrolube, [buy it here](https://air-hobby.ru/katalog/product/2286-dca-electrolube-prozrachniy-lak-na-osnove-modifitsirovannogo-silikona-20ml.html)&quot;">​</a></h2><p>Varnish. Sold in a convenient tube with a brush. Similar to 422C (see Legacy): liquid, dries in 30+ minutes, slightly viscous when cured. Can peel off after cooling. Generally fewer positive reviews than the alternatives above.</p><ul><li><p>Mid-range price (550 RUB for 25ml)</p></li><li><p>Easy application</p></li><li><p>Long drying time</p></li><li><p>Does not guarantee 100% protection</p></li></ul><p align="center"><img src="'+i+'" width="600" alt="DCA Electrolube"></p><h2 id="spinner-protection-silicone-conformal-coating-v2-spinner-liquid-v2-buy-it-here" tabindex="-1">Spinner Protection Silicone Conformal Coating V2 (&quot;Spinner Liquid V2&quot;), <a href="https://www.spinnerproduction.ru/catalog-0-846" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#spinner-protection-silicone-conformal-coating-v2-spinner-liquid-v2-buy-it-here" aria-label="Permalink to &quot;Spinner Protection Silicone Conformal Coating V2 (&quot;Spinner Liquid V2&quot;), [buy it here](https://www.spinnerproduction.ru/catalog-0-846)&quot;">​</a></h2><p>Varnish. Many might assume it&#39;s DCA or 422C, but it has a different formula (according to the seller). I haven&#39;t personally tested it (if you have experience, please supplement the article). Costs 600 RUB for 20ml. Reviews suggest behavior similar to 422C—long drying time and imperfect protection.</p><p align="center"><img src="'+s+'" width="600" alt="Spinner Liquid"></p><h2 id="chinese-ip65-circuit-protection-buy-it-here" tabindex="-1">Chinese IP65 Circuit Protection, <a href="https://a.aliexpress.com/_mKX5LuM" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#chinese-ip65-circuit-protection-buy-it-here" aria-label="Permalink to &quot;Chinese IP65 Circuit Protection, [buy it here](https://a.aliexpress.com/_mKX5LuM)&quot;">​</a></h2><p>Varnish. Similar to 422B but more viscous. Also has a pungent smell. Sets in 15 minutes; for full drying, it&#39;s better to wait a day, as with other varnishes. One layer is sufficient. You can solder through it, and it can be cleaned off with a brush and acetone. In my personal experience, it hasn&#39;t failed or cracked yet. Better not to leave the tube open as it thickens. The volume will last a very long time; it will dry out before you use it all unless you decant it into smaller tubes. Summary:</p><ul><li>Cheap ($8 for 100ml)</li><li>More trustworthy than alternatives like 422C, DCA, or Spinner V2</li><li>Easily cleaned off</li><li>Fast drying</li><li>Good adhesion</li><li>Can solder through it</li></ul><ul><li>Not the most accessible option (AliExpress only)</li><li>Pungent smell</li></ul><p align="center"><img src="'+i+'" width="600" alt="ip65"></p><h2 id="liquid-electrical-tape" tabindex="-1">Liquid Electrical Tape <a class="header-anchor" href="#liquid-electrical-tape" aria-label="Permalink to &quot;Liquid Electrical Tape&quot;">​</a></h2><p>Another option mentioned, though not very popular, is liquid electrical tape. Degrease the electronics with alcohol, dry, and apply a layer. It dries in 15-20 minutes. It peels off in one layer like tape. A 500ml spray costs up to 900 RUB. If you have experience using this, please supplement the article.</p><h2 id="legacy" tabindex="-1">Legacy: <a class="header-anchor" href="#legacy" aria-label="Permalink to &quot;Legacy:&quot;">​</a></h2><h3 id="plastik-71-buy-it-here" tabindex="-1">Plastik-71, <a href="https://www.chipdip.ru/product/plastik-71-100" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#plastik-71-buy-it-here" aria-label="Permalink to &quot;Plastik-71, [buy it here](https://www.chipdip.ru/product/plastik-71-100)&quot;">​</a></h3><p>Varnish. Plastik-71 initially gained popularity as the most accessible option available in every electronics shop, but it&#39;s a poor choice because it cracks quickly under use, letting moisture in. Multiple layers can be applied to increase longevity, but there are no real guarantees. Some believe quality varies by manufacturer, with a few positive reviews, but they are rare. Summary:</p><ul><li><p>Cheap (under 200 RUB for up to 100ml)</p></li><li><p>Widely available</p></li><li><p>Does not guarantee waterproofing as it cracks over time.</p></li></ul><p><strong>Not recommended by hobbyists.</strong></p><h3 id="mg-chemicals-422b-discontinued" tabindex="-1">MG Chemicals 422B, <a href="https://www.farnell.com/datasheets/2614568.pdf" target="_blank" rel="noreferrer">discontinued</a> <a class="header-anchor" href="#mg-chemicals-422b-discontinued" aria-label="Permalink to &quot;MG Chemicals 422B, [discontinued](https://www.farnell.com/datasheets/2614568.pdf)&quot;">​</a></h3><p>Varnish. For a long time, it was relatively accessible, sold in small jars at ChipDip and in 20-25ml tubes by Spinner Production and Air-Hobby (under the names &quot;Spinner Liquid&quot; or later &quot;Air-Hobby 422B&quot;). It was a compromise, costing around 300-400 RUB for 20ml (enough for a year of active use). Set in 10 minutes, cured in 15, though 24 hours at room temperature was recommended for full drying. One layer was sufficient for protection, but at low temperatures (winter flying), it would start to crack and let moisture in. Production stopped in 2021; it is no longer available. The 422C version became the alternative.</p><h3 id="mg-chemicals-422c-phasing-out" tabindex="-1">MG Chemicals 422C, <a href="https://www.mgchemicals.com/products/conformal-coatings/silicone-conformal-coatings/conformal-coating-waterproof/" target="_blank" rel="noreferrer">phasing out</a> <a class="header-anchor" href="#mg-chemicals-422c-phasing-out" aria-label="Permalink to &quot;MG Chemicals 422C, [phasing out](https://www.mgchemicals.com/products/conformal-coatings/silicone-conformal-coatings/conformal-coating-waterproof/)&quot;">​</a></h3><p>Varnish. There are many mixed reviews; I haven&#39;t personally tried it. Presumably similar to 422B but more liquid and takes longer to dry (30-40 minutes per layer). For a while, it was sold under the same names as 422B, but it is now gradually disappearing from stores. Summary:</p><ul><li><p>Mid-range price (around 700 RUB for 20ml in 2022)</p></li><li><p>Can solder through it</p></li><li><p>Easily removed with a brush and alcohol or acetone</p></li><li><p>Becoming hard to find in Russia</p></li><li><p>Long drying time</p></li><li><p>Does not guarantee 100% protection</p></li></ul><h3 id="fx-fpv-aerox-discontinued" tabindex="-1">FX FPV AeroX, <a href="https://quadro.team/goods/aerox" target="_blank" rel="noreferrer">discontinued</a> <a class="header-anchor" href="#fx-fpv-aerox-discontinued" aria-label="Permalink to &quot;FX FPV AeroX, [discontinued](https://quadro.team/goods/aerox)&quot;">​</a></h3><p>Silicone. Odorless. Sets in 15 minutes (still tacky but no longer runs), cures in 30 minutes. Removed in flakes after soaking for 15 minutes in a container with heptane + isopropanol, or by scraping it off in pieces. Soldering through it is impossible. The brush made it easy to apply thin layers, leading to lower consumption than tube alternatives. Mantains integrity without external interference. However, after opening and a few uses over a month, it thickened so much it became unusable, despite being tightly capped. Cannot be diluted with alcohol. Summary:</p><ul><li><p>Reliable protection</p></li><li><p>Good adhesion</p></li><li><p>Odorless</p></li><li><p>Removal requires soaking in heptane + isopropanol for 15 min or scraping</p></li><li><p>Only available in Russia</p></li><li><p>Expensive (950 RUB for 20ml)</p></li><li><p>Short shelf life after opening</p></li><li><p>Cannot solder through it</p></li></ul><h3 id="antas-zs-nj-d955-silicone-varnish-buy-it-here" tabindex="-1">Antas ZS-NJ-D955 Silicone Varnish, <a href="https://quadro.team/goods/Vysokoprochnoe-konformnoe-silikonovoe-pokrytie-Antas-ZS-NJ-D955-Keks-Edition?mod_id=300898141" target="_blank" rel="noreferrer">buy it here</a> <a class="header-anchor" href="#antas-zs-nj-d955-silicone-varnish-buy-it-here" aria-label="Permalink to &quot;Antas ZS-NJ-D955 Silicone Varnish, [buy it here](https://quadro.team/goods/Vysokoprochnoe-konformnoe-silikonovoe-pokrytie-Antas-ZS-NJ-D955-Keks-Edition?mod_id=300898141)&quot;">​</a></h3><p>Varnish. Sold in a convenient tube with a brush. Sets in 10-15 minutes. Curing can be accelerated with heat. The cured layer is not viscous.</p>',63)])])}const q=p(d,[["render",m]]);export{_ as __pageData,q as default};
